import React, { useState, useCallback, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { getHealth, runDetection, runEnhance, downloadPDF, runVideoDetection } from "./api";

/* ═══════════════ Helpers ═══════════════ */
const SEV_MAP = {
  "Marine Growth": "critical", Corrosion: "critical",
  "Sea Chest Blockage": "high", Crack: "high",
  "Biofouling": "high", Paint: "medium", Anode: "medium",
  "Crack / Fracture / Corrosion": "critical",
};
const sev = cls => SEV_MAP[cls] || "low";
const pct = v => `${(v * 100).toFixed(1)}%`;
const fadeProps = { initial: { opacity: 0, y: 12 }, animate: { opacity: 1, y: 0 }, exit: { opacity: 0, y: -8 }, transition: { duration: 0.3 } };

/* ═══════════════ Sub-components ═══════════════ */

/* Drop-zone */
function DropZone({ onFile, accept, label }) {
  const ref = useRef(null);
  const [dragging, setDragging] = useState(false);
  const [fileName, setFileName] = useState(null);
  const handle = e => { e.preventDefault(); setDragging(false); const f = e.dataTransfer?.files?.[0] || e.target?.files?.[0]; if (f) { setFileName(f.name); onFile(f); } };
  return (
    <div className={`dropzone${dragging ? " active" : ""}`}
      onDragOver={e => { e.preventDefault(); setDragging(true); }}
      onDragLeave={() => setDragging(false)}
      onDrop={handle}
      onClick={() => ref.current?.click()}>
      <input ref={ref} type="file" accept={accept} style={{ display: "none" }} onChange={handle} />
      <div className="dz-icon">🛰️</div>
      <div className="dz-text">{label || "Drop image or click to upload"}</div>
      <div className="dz-hint">JPG / PNG — Max 10 MB</div>
      {fileName && <div className="dz-file">{fileName}</div>}
    </div>
  );
}

/* Toggle */
function Toggle({ label, value, onChange }) {
  return (
    <label className="ctrl-toggle">
      <span className="tgl"><input type="checkbox" checked={value} onChange={e => onChange(e.target.checked)} /><span className="tgl-track" /><span className="tgl-dot" /></span>
      <span>{label}</span>
    </label>
  );
}

/* Slider */
function Slider({ label, min, max, step, value, onChange }) {
  return (
    <div className="ctrl">
      <div className="ctrl-label"><span>{label}</span><span>{value}</span></div>
      <input className="ctrl-slider" type="range" min={min} max={max} step={step} value={value} onChange={e => onChange(+e.target.value)} />
    </div>
  );
}

/* Metric tile */
function Metric({ label, value, color }) {
  return <div className="m"><div className="m-label">{label}</div><div className={`m-val ${color || ""}`}>{value}</div></div>;
}

/* ═══════════════ TABS DATA ═══════════════ */
const TABS = [
  { key: "scan", icon: "🔍", label: "Infrastructure Scan" },
  { key: "hull", icon: "🚢", label: "Hull Inspection" },
  { key: "video", icon: "🎬", label: "Video Analysis" },
  { key: "pipeline", icon: "🔧", label: "Pipeline & Subsea" },
  { key: "cable", icon: "🔌", label: "Cable Anomaly" },
  { key: "dash", icon: "📊", label: "Mission Dashboard" },
  { key: "road", icon: "🗺️", label: "Roadmap" },
];

/* ═══════════════ MAIN APP ═══════════════ */
export default function App() {
  const [tab, setTab] = useState("scan");
  const [health, setHealth] = useState(null);

  /* Shared detection state */
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  /* Enhancement state */
  const [enhFile, setEnhFile] = useState(null);
  const [enhResult, setEnhResult] = useState(null);

  /* Video state */
  const [vidFile, setVidFile] = useState(null);
  const [vidResult, setVidResult] = useState(null);

  /* Hull / Pipeline / Cable use same detect flow with different context */
  const [hullFile, setHullFile] = useState(null);
  const [hullResult, setHullResult] = useState(null);
  const [pipeFile, setPipeFile] = useState(null);
  const [pipeResult, setPipeResult] = useState(null);
  const [cableFile, setCableFile] = useState(null);
  const [cableResult, setCableResult] = useState(null);

  /* Detection params */
  const [conf, setConf] = useState(0.35);
  const [iou, setIou] = useState(0.50);
  const [maxDet, setMaxDet] = useState(300);
  const [useClahe, setUseClahe] = useState(true);
  const [useGreen, setUseGreen] = useState(true);
  const [turbIn, setTurbIn] = useState(0.4);
  const [corrTurb, setCorrTurb] = useState(0.25);
  const [clipLim, setClipLim] = useState(2.0);
  const [useEdge, setUseEdge] = useState(false);
  const [marineSnow, setMarineSnow] = useState(false);

  const detParams = { conf, iou, max_det: maxDet };
  const enhParams = { use_clahe: useClahe, use_green: useGreen, turb_in: turbIn, corr_turb: corrTurb, use_edge: useEdge, clahe_clip: clipLim, marine_snow: marineSnow };

  useEffect(() => { getHealth().then(setHealth).catch(() => {}); }, []);

  /* Detect handler — generic */
  const detect = useCallback(async (f, setter) => {
    if (!f) return;
    setLoading(true); setError(null);
    try { const res = await runDetection(f, detParams); setter(res); }
    catch (e) { setError(e.response?.data?.detail || e.message); }
    finally { setLoading(false); }
  }, [conf, iou, maxDet]);

  /* Enhance handler */
  const enhance = useCallback(async () => {
    if (!enhFile) return;
    setLoading(true); setError(null);
    try { const res = await runEnhance(enhFile, enhParams); setEnhResult(res); }
    catch (e) { setError(e.response?.data?.detail || e.message); }
    finally { setLoading(false); }
  }, [enhFile, useClahe, useGreen, turbIn, corrTurb, clipLim, useEdge, marineSnow]);

  /* Video handler */
  const analyzeVideo = useCallback(async () => {
    if (!vidFile) return;
    setLoading(true); setError(null);
    try { const res = await runVideoDetection(vidFile, { conf, iou, max_det: maxDet }); setVidResult(res); }
    catch (e) { setError(e.response?.data?.detail || e.message); }
    finally { setLoading(false); }
  }, [vidFile, conf, iou, maxDet]);

  /* PDF */
  const genPDF = useCallback(async (f) => {
    if (!f) return; setLoading(true);
    try { await downloadPDF(f, { conf, iou, max_det: maxDet }); }
    catch (e) { setError(e.response?.data?.detail || e.message); }
    finally { setLoading(false); }
  }, [conf, iou, maxDet]);

  /* ─── Render helpers ─── */

  function renderDetectionResults(res) {
    if (!res) return null;
    const dets = res.detections || [];
    const counts = {};
    dets.forEach(d => { const c = d.class_name; counts[c] = (counts[c] || 0) + 1; });
    const total = dets.length;
    const criticals = dets.filter(d => sev(d.class_name) === "critical").length;
    const highs = dets.filter(d => sev(d.class_name) === "high").length;
    const risk = res.risk_score ?? (total > 0 ? Math.min(100, total * 8 + criticals * 15 + highs * 8) : 0);
    const grade = res.grade ?? (risk < 20 ? "A" : risk < 40 ? "B" : risk < 60 ? "C" : risk < 80 ? "D" : "F");
    return (
      <motion.div {...fadeProps}>
        {/* Metrics strip */}
        <div className="metrics">
          <Metric label="Total Detections" value={total} color="t-ok" />
          <Metric label="Critical" value={criticals} color="t-danger" />
          <Metric label="High" value={highs} color="t-warn" />
          <Metric label="Risk Score" value={`${risk.toFixed?.(1) ?? risk}%`} color={risk > 60 ? "t-danger" : risk > 30 ? "t-warn" : "t-success"} />
          <Metric label="Grade" value={grade} color={grade === "A" ? "t-success" : grade === "F" ? "t-danger" : "t-warn"} />
        </div>

        {/* Risk bar */}
        <div className="card risk-block">
          <div className="risk-row">
            <div className="risk-score">{risk.toFixed?.(1) ?? risk}<span className="risk-unit">%</span></div>
            <div className="risk-msg" style={{ color: risk > 60 ? "#FB7185" : risk > 30 ? "#FBBF24" : "#34D399" }}>
              {risk > 60 ? "⚠ Critical — immediate inspection required" : risk > 30 ? "Moderate risk — schedule maintenance" : "Low risk — structure in good condition"}
            </div>
          </div>
          <div className="risk-track"><div className="risk-fill" style={{ width: `${Math.min(risk, 100)}%` }} /></div>
          <div className="risk-legend"><span style={{ color: "#34D399" }}>Low</span><span style={{ color: "#FBBF24" }}>Moderate</span><span style={{ color: "#FB7185" }}>Critical</span></div>
        </div>

        {/* Images */}
        <div className="ig ig-2 mb-16">
          {res.annotated_b64 && (
            <div className="img-f"><div className="img-label">ANNOTATED</div><img alt="annotated" src={`data:image/jpeg;base64,${res.annotated_b64}`} /></div>
          )}
          {res.heatmap_b64 && (
            <div className="img-f"><div className="img-label">HEATMAP</div><img alt="heatmap" src={`data:image/jpeg;base64,${res.heatmap_b64}`} /></div>
          )}
        </div>

        {/* Table */}
        {dets.length > 0 && (
          <div className="card">
            <div className="card-header">Detection Log — {dets.length} findings</div>
            <table className="det-table">
              <thead><tr><th>#</th><th>Class</th><th>Severity</th><th>Confidence</th><th>BBox (xywh)</th></tr></thead>
              <tbody>
                {dets.map((d, i) => (
                  <tr key={i}>
                    <td className="cell-mono">{i + 1}</td>
                    <td className="cell-bold">{d.class_name}</td>
                    <td><span className={`sev sev-${sev(d.class_name)}`}>{sev(d.class_name).toUpperCase()}</span></td>
                    <td className="cell-mono">{pct(d.confidence)}</td>
                    <td className="cell-mono">{d.bbox?.map(v => Math.round(v)).join(", ") || "—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* Class breakdown */}
        {Object.keys(counts).length > 0 && (
          <div className="card mt-12">
            <div className="card-header">Class Distribution</div>
            <div className="metrics">
              {Object.entries(counts).map(([cls, n]) => (
                <Metric key={cls} label={cls} value={n} color={`t-${sev(cls) === "critical" ? "danger" : sev(cls) === "high" ? "warn" : "ok"}`} />
              ))}
            </div>
          </div>
        )}
      </motion.div>
    );
  }

  /* ─── Tab: Scan (detection + enhancement) ─── */
  function TabScan() {
    return (
      <motion.div key="scan" {...fadeProps}>
        <div className="sec">
          <div className="sec-crumb">NautiCAI &gt; Infrastructure Scan</div>
          <div className="sec-title">Underwater Infrastructure Scan</div>
          <div className="sec-sub">Upload an underwater image to detect anomalies, corrosion, marine growth, and structural defects using our YOLOv8 model.</div>
          <div className="sec-line" />
        </div>

        <div className="row" style={{ alignItems: "flex-start" }}>
          <div className="col" style={{ maxWidth: 380 }}>
            <div className="card">
              <div className="card-header">Image Upload</div>
              <DropZone onFile={f => { setFile(f); setResult(null); }} accept="image/*" />
              <button className="btn btn-primary btn-block mt-12" disabled={!file || loading} onClick={() => detect(file, setResult)}>
                {loading ? <><span className="spinner" /> Analyzing…</> : "🔍  Run Detection"}
              </button>
              <button className="btn btn-secondary btn-block mt-8" disabled={!file || loading} onClick={() => genPDF(file)}>
                📄  Generate PDF Report
              </button>
            </div>
          </div>
          <div className="col">
            {error && <div className="alert alert-warn">⚠ {error}</div>}
            {!result && !loading && <div className="preview"><div className="preview-ph">Upload an image and click <strong>Run Detection</strong> to see results</div></div>}
            {loading && !result && <div className="preview"><div className="preview-ph"><span className="spinner" style={{ width: 28, height: 28 }} /> <br />Processing…</div></div>}
            {renderDetectionResults(result)}
          </div>
        </div>

        {/* Enhancement section */}
        <div className="sec mt-16">
          <div className="sec-title" style={{ fontSize: 18 }}>🌊 Visibility Enhancement</div>
          <div className="sec-sub">Improve underwater image clarity with CLAHE, green-water correction, turbidity estimation, and edge enhancement.</div>
          <div className="sec-line" />
        </div>
        <div className="row" style={{ alignItems: "flex-start" }}>
          <div className="col" style={{ maxWidth: 380 }}>
            <div className="card">
              <div className="card-header">Enhancement Upload</div>
              <DropZone onFile={f => { setEnhFile(f); setEnhResult(null); }} accept="image/*" label="Drop image for enhancement" />
              <button className="btn btn-primary btn-block mt-12" disabled={!enhFile || loading} onClick={enhance}>
                {loading ? <><span className="spinner" /> Enhancing…</> : "✨  Enhance Image"}
              </button>
            </div>
          </div>
          <div className="col">
            {enhResult && (
              <motion.div {...fadeProps}>
                {enhResult.metrics && (
                  <div className="metrics mb-12">
                    {enhResult.metrics.psnr != null && <Metric label="PSNR" value={enhResult.metrics.psnr.toFixed(2)} color="t-ok" />}
                    {enhResult.metrics.ssim != null && <Metric label="SSIM" value={enhResult.metrics.ssim.toFixed(4)} color="t-success" />}
                    {enhResult.metrics.uiqm != null && <Metric label="UIQM" value={enhResult.metrics.uiqm.toFixed(3)} color="t-warn" />}
                  </div>
                )}
                <div className="ig ig-2">
                  {enhResult.original_b64 && <div className="img-f"><div className="img-label">ORIGINAL</div><img alt="original" src={`data:image/jpeg;base64,${enhResult.original_b64}`} /></div>}
                  {enhResult.enhanced_b64 && <div className="img-f"><div className="img-label">ENHANCED</div><img alt="enhanced" src={`data:image/jpeg;base64,${enhResult.enhanced_b64}`} /></div>}
                </div>
                {enhResult.steps && Object.keys(enhResult.steps).length > 0 && (
                  <div className="ig ig-4 mt-12">
                    {Object.entries(enhResult.steps).map(([k, b64]) => (
                      <div className="img-f" key={k}><div className="img-label">{k.toUpperCase()}</div><img alt={k} src={`data:image/jpeg;base64,${b64}`} /></div>
                    ))}
                  </div>
                )}
              </motion.div>
            )}
            {!enhResult && <div className="preview"><div className="preview-ph">Upload an image and click <strong>Enhance</strong> to compare</div></div>}
          </div>
        </div>
      </motion.div>
    );
  }

  /* ─── Tab: Hull ─── */
  function TabHull() {
    return (
      <motion.div key="hull" {...fadeProps}>
        <div className="sec">
          <div className="sec-crumb">NautiCAI &gt; Hull Inspection</div>
          <div className="sec-title">🚢 Hull Inspection Module</div>
          <div className="sec-sub">Detect biofouling, marine growth, corrosion, and structural damage on ship hulls. Supports detection across hull components: bilge keel, propeller, rudder, sea chest, and thruster areas.</div>
          <div className="sec-line" />
        </div>
        <div className="row" style={{ alignItems: "flex-start" }}>
          <div className="col" style={{ maxWidth: 380 }}>
            <div className="card">
              <div className="card-header">Hull Image</div>
              <DropZone onFile={f => { setHullFile(f); setHullResult(null); }} accept="image/*" label="Drop hull inspection image" />
              <button className="btn btn-primary btn-block mt-12" disabled={!hullFile || loading} onClick={() => detect(hullFile, setHullResult)}>
                {loading ? <><span className="spinner" /> Scanning…</> : "🚢  Scan Hull"}
              </button>
              <button className="btn btn-secondary btn-block mt-8" disabled={!hullFile || loading} onClick={() => genPDF(hullFile)}>
                📄  Hull Report PDF
              </button>
            </div>
          </div>
          <div className="col">
            {error && <div className="alert alert-warn">⚠ {error}</div>}
            {!hullResult && !loading && <div className="preview"><div className="preview-ph">Upload a hull image and click <strong>Scan Hull</strong></div></div>}
            {renderDetectionResults(hullResult)}
          </div>
        </div>
      </motion.div>
    );
  }

  /* ─── Tab: Video ─── */
  function TabVideo() {
    return (
      <motion.div key="video" {...fadeProps}>
        <div className="sec">
          <div className="sec-crumb">NautiCAI &gt; Video Analysis</div>
          <div className="sec-title">🎬 Video Anomaly Detection</div>
          <div className="sec-sub">Upload an underwater inspection video (MP4). The system will process frames, detect anomalies, and provide a comprehensive per-frame analysis.</div>
          <div className="sec-line" />
        </div>
        <div className="row" style={{ alignItems: "flex-start" }}>
          <div className="col" style={{ maxWidth: 380 }}>
            <div className="card">
              <div className="card-header">Video Upload</div>
              <DropZone onFile={f => { setVidFile(f); setVidResult(null); }} accept="video/*" label="Drop MP4 video file" />
              <button className="btn btn-primary btn-block mt-12" disabled={!vidFile || loading} onClick={analyzeVideo}>
                {loading ? <><span className="spinner" /> Analyzing Video…</> : "🎬  Analyze Video"}
              </button>
            </div>
            {vidResult && (
              <div className="card mt-12">
                <div className="card-header">Video Summary</div>
                <div className="metrics">
                  <Metric label="Frames" value={vidResult.total_frames ?? "—"} color="t-ok" />
                  <Metric label="Processed" value={vidResult.processed_frames ?? "—"} color="t-success" />
                  <Metric label="Detections" value={vidResult.total_detections ?? "—"} color="t-warn" />
                </div>
              </div>
            )}
          </div>
          <div className="col">
            {error && <div className="alert alert-warn">⚠ {error}</div>}
            {!vidResult && !loading && <div className="preview"><div className="preview-ph">Upload a video and click <strong>Analyze Video</strong></div></div>}
            {loading && !vidResult && <div className="preview"><div className="preview-ph"><span className="spinner" style={{ width: 28, height: 28 }} /><br />Processing video frames…<br /><span style={{ fontSize: 11, color: "#5A6890" }}>This may take a minute</span></div></div>}
            {vidResult?.frames && vidResult.frames.length > 0 && (
              <motion.div {...fadeProps}>
                <div className="card">
                  <div className="card-header">Per-Frame Results</div>
                  <table className="det-table">
                    <thead><tr><th>Frame</th><th>Detections</th><th>Classes</th></tr></thead>
                    <tbody>
                      {vidResult.frames.slice(0, 50).map((fr, i) => (
                        <tr key={i}>
                          <td className="cell-mono">{fr.frame_idx ?? i}</td>
                          <td className="cell-mono">{fr.count ?? fr.detections?.length ?? 0}</td>
                          <td>{(fr.classes || fr.detections?.map(d => d.class_name) || []).join(", ") || "—"}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
                {vidResult.frames.filter(f => f.annotated_b64).length > 0 && (
                  <div className="ig ig-4 mt-12">
                    {vidResult.frames.filter(f => f.annotated_b64).slice(0, 12).map((fr, i) => (
                      <div className="img-f" key={i}><div className="img-label">F{fr.frame_idx ?? i}</div><img alt={`frame-${i}`} src={`data:image/jpeg;base64,${fr.annotated_b64}`} /></div>
                    ))}
                  </div>
                )}
              </motion.div>
            )}
          </div>
        </div>
      </motion.div>
    );
  }

  /* ─── Tab: Pipeline & Subsea ─── */
  function TabPipeline() {
    return (
      <motion.div key="pipeline" {...fadeProps}>
        <div className="sec">
          <div className="sec-crumb">NautiCAI &gt; Pipeline &amp; Subsea Analysis</div>
          <div className="sec-title">🔧 Pipeline & Subsea Scan</div>
          <div className="sec-sub">Detect cracks, corrosion, marine growth, and damage on subsea pipelines, risers, and underwater infrastructure.</div>
          <div className="sec-line" />
        </div>
        <div className="row" style={{ alignItems: "flex-start" }}>
          <div className="col" style={{ maxWidth: 380 }}>
            <div className="card">
              <div className="card-header">Pipeline Image</div>
              <DropZone onFile={f => { setPipeFile(f); setPipeResult(null); }} accept="image/*" label="Drop pipeline/subsea image" />
              <button className="btn btn-primary btn-block mt-12" disabled={!pipeFile || loading} onClick={() => detect(pipeFile, setPipeResult)}>
                {loading ? <><span className="spinner" /> Scanning…</> : "🔧  Scan Pipeline"}
              </button>
              <button className="btn btn-secondary btn-block mt-8" disabled={!pipeFile || loading} onClick={() => genPDF(pipeFile)}>
                📄  Pipeline Report
              </button>
            </div>
          </div>
          <div className="col">
            {error && <div className="alert alert-warn">⚠ {error}</div>}
            {!pipeResult && !loading && <div className="preview"><div className="preview-ph">Upload a pipeline image and click <strong>Scan Pipeline</strong></div></div>}
            {renderDetectionResults(pipeResult)}
          </div>
        </div>
      </motion.div>
    );
  }

  /* ─── Tab: Cable ─── */
  function TabCable() {
    return (
      <motion.div key="cable" {...fadeProps}>
        <div className="sec">
          <div className="sec-crumb">NautiCAI &gt; Cable Anomaly Detection</div>
          <div className="sec-title">🔌 Subsea Cable Anomaly</div>
          <div className="sec-sub">Detect damage, abrasion, exposure, and biofouling on subsea power and telecommunications cables.</div>
          <div className="sec-line" />
        </div>
        <div className="row" style={{ alignItems: "flex-start" }}>
          <div className="col" style={{ maxWidth: 380 }}>
            <div className="card">
              <div className="card-header">Cable Image</div>
              <DropZone onFile={f => { setCableFile(f); setCableResult(null); }} accept="image/*" label="Drop cable inspection image" />
              <button className="btn btn-primary btn-block mt-12" disabled={!cableFile || loading} onClick={() => detect(cableFile, setCableResult)}>
                {loading ? <><span className="spinner" /> Scanning…</> : "🔌  Scan Cable"}
              </button>
              <button className="btn btn-secondary btn-block mt-8" disabled={!cableFile || loading} onClick={() => genPDF(cableFile)}>
                📄  Cable Report
              </button>
            </div>
          </div>
          <div className="col">
            {error && <div className="alert alert-warn">⚠ {error}</div>}
            {!cableResult && !loading && <div className="preview"><div className="preview-ph">Upload a cable image and click <strong>Scan Cable</strong></div></div>}
            {renderDetectionResults(cableResult)}
          </div>
        </div>
      </motion.div>
    );
  }

  /* ─── Tab: Dashboard ─── */
  function TabDashboard() {
    const totalDets = [result, hullResult, pipeResult, cableResult].reduce((s, r) => s + (r?.detections?.length || 0), 0);
    const allDets = [result, hullResult, pipeResult, cableResult].flatMap(r => r?.detections || []);
    const classCounts = {};
    allDets.forEach(d => { classCounts[d.class_name] = (classCounts[d.class_name] || 0) + 1; });
    const modules = [
      { name: "Infrastructure", dets: result?.detections?.length || 0 },
      { name: "Hull", dets: hullResult?.detections?.length || 0 },
      { name: "Pipeline", dets: pipeResult?.detections?.length || 0 },
      { name: "Cable", dets: cableResult?.detections?.length || 0 },
    ];
    return (
      <motion.div key="dash" {...fadeProps}>
        <div className="sec">
          <div className="sec-crumb">NautiCAI &gt; Mission Dashboard</div>
          <div className="sec-title">📊 Mission Dashboard</div>
          <div className="sec-sub">Aggregated overview of all detection modules. Run scans in the other tabs to populate this dashboard.</div>
          <div className="sec-line" />
        </div>

        <div className="metrics">
          <Metric label="Total Detections" value={totalDets} color="t-ok" />
          <Metric label="Modules Active" value={modules.filter(m => m.dets > 0).length} color="t-success" />
          <Metric label="Classes Found" value={Object.keys(classCounts).length} color="t-warn" />
          <Metric label="Model" value={health?.model || "—"} />
        </div>

        <div className="card">
          <div className="card-header">Module Breakdown</div>
          <table className="det-table">
            <thead><tr><th>Module</th><th>Detections</th><th>Status</th></tr></thead>
            <tbody>
              {modules.map(m => (
                <tr key={m.name}>
                  <td className="cell-bold">{m.name}</td>
                  <td className="cell-mono">{m.dets}</td>
                  <td>{m.dets > 0 ? <span className="sev sev-medium">SCANNED</span> : <span style={{ color: "#5A6890", fontSize: 12 }}>Pending</span>}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {Object.keys(classCounts).length > 0 && (
          <div className="card mt-12">
            <div className="card-header">All Detected Classes</div>
            <div className="metrics">
              {Object.entries(classCounts).sort((a, b) => b[1] - a[1]).map(([cls, n]) => (
                <Metric key={cls} label={cls} value={n} color={`t-${sev(cls) === "critical" ? "danger" : sev(cls) === "high" ? "warn" : "ok"}`} />
              ))}
            </div>
          </div>
        )}

        {totalDets === 0 && (
          <div className="alert alert-info mt-12">ℹ No scans have been run yet. Use the Infrastructure, Hull, Pipeline, or Cable tabs to run detections.</div>
        )}
      </motion.div>
    );
  }

  /* ─── Tab: Roadmap ─── */
  function TabRoadmap() {
    const phases = [
      { name: "α", tag: "LIVE", tagCls: "live", count: "6", unit: "/6", det: "ACTIVE MODULES", items: ["YOLOv8 Multi-Class Detection", "Visibility Enhancement (CLAHE + Green Correction)", "PDF Report Generation with QR Codes", "Hull / Pipeline / Cable Scanning", "Video Frame-by-Frame Analysis", "Risk Scoring & Grading"] },
      { name: "β", tag: "Q3 2025", tagCls: "planned", count: "5", unit: "/5", det: "PLANNED MODULES", items: ["Edge-Deployed Lite Model (ONNX)", "Temporal Anomaly Tracking", "Real-Time ROV Video Streaming", "Multi-Sensor Fusion (Sonar + Camera)", "Automated Maintenance Scheduling"] },
      { name: "γ", tag: "Q1 2026", tagCls: "planned", count: "4", unit: "/4", det: "FUTURE MODULES", items: ["3D Mesh Reconstruction from Video", "Digital Twin Integration", "Natural Language Report Queries", "Fleet-Wide Analytics Dashboard"] },
    ];
    return (
      <motion.div key="road" {...fadeProps}>
        <div className="sec">
          <div className="sec-crumb">NautiCAI &gt; Product Roadmap</div>
          <div className="sec-title">🗺️ Development Roadmap</div>
          <div className="sec-sub">NautiCAI's phased evolution from single-image detection to a full-stack maritime intelligence platform.</div>
          <div className="sec-line" />
        </div>
        <div className="phase-grid">
          {phases.map(p => (
            <div className="phase" key={p.name}>
              <div className="phase-hdr">
                <div className="phase-name">{p.name}</div>
                <div className={`phase-tag ${p.tagCls}`}>{p.tag}</div>
              </div>
              <div className="phase-count">{p.count}<span>{p.unit}</span></div>
              <div className="phase-det">{p.det}</div>
              <ul style={{ paddingLeft: 14, listStyle: "none" }}>
                {p.items.map((it, i) => (
                  <li key={i} style={{ fontSize: 12, color: "#C5D0E6", marginBottom: 6, display: "flex", alignItems: "center", gap: 6 }}>
                    <span style={{ width: 5, height: 5, borderRadius: "50%", background: p.tagCls === "live" ? "#34D399" : "#5A6890", flexShrink: 0 }} />
                    {it}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>

        <div className="card mt-12">
          <div className="card-header">Technology Stack</div>
          <div className="metrics">
            <Metric label="Detection" value="YOLOv8" color="t-ok" />
            <Metric label="Backend" value="FastAPI" color="t-success" />
            <Metric label="Frontend" value="React" color="t-warn" />
            <Metric label="Cloud" value="GCP" color="t-ok" />
            <Metric label="Vision" value="OpenCV" color="t-success" />
            <Metric label="Reports" value="ReportLab" color="t-warn" />
          </div>
        </div>
      </motion.div>
    );
  }

  /* ─── Tab renderer ─── */
  function renderTab() {
    switch (tab) {
      case "scan": return <TabScan />;
      case "hull": return <TabHull />;
      case "video": return <TabVideo />;
      case "pipeline": return <TabPipeline />;
      case "cable": return <TabCable />;
      case "dash": return <TabDashboard />;
      case "road": return <TabRoadmap />;
      default: return <TabScan />;
    }
  }

  /* ═══════════════ RENDER ═══════════════ */
  return (
    <>
      <div className="aurora" />
      <div className="app">
        {/* ── Sidebar ── */}
        <aside className="sidebar">
          <div className="sb-brand">
            <div className="sb-icon">🤿</div>
            <div><h3>NAUTICAI</h3><p>Maritime Intelligence</p></div>
          </div>

          <div className="sb-pills">
            <span className="pill"><span className={`dot ${health ? "dot-ok" : "dot-warn"}`} />{health ? "Online" : "Connecting…"}</span>
            <span className="pill">{health?.model || "best.pt"}</span>
          </div>

          {health && <div className="model-badge">✓ Model loaded · v{health.version || "1.0"}</div>}

          <div className="sb-divider" />
          <div className="sb-heading">Detection</div>

          <Slider label="Confidence" min={0.05} max={0.95} step={0.05} value={conf} onChange={setConf} />
          <Slider label="IoU Threshold" min={0.1} max={0.95} step={0.05} value={iou} onChange={setIou} />
          <Slider label="Max Detections" min={50} max={1000} step={50} value={maxDet} onChange={setMaxDet} />

          <div className="sb-divider" />
          <div className="sb-heading">Enhancement</div>

          <Toggle label="CLAHE Enhancement" value={useClahe} onChange={setUseClahe} />
          <Toggle label="Green-Water Correction" value={useGreen} onChange={setUseGreen} />
          <Toggle label="Edge Enhancement" value={useEdge} onChange={setUseEdge} />
          <Toggle label="Marine Snow Filter" value={marineSnow} onChange={setMarineSnow} />

          <Slider label="Turbidity Input" min={0} max={1} step={0.05} value={turbIn} onChange={setTurbIn} />
          <Slider label="Correction Factor" min={0} max={1} step={0.05} value={corrTurb} onChange={setCorrTurb} />
          <Slider label="CLAHE Clip Limit" min={0.5} max={5} step={0.25} value={clipLim} onChange={setClipLim} />

          <div style={{ flex: 1 }} />
          <div className="sb-divider" />
          <div style={{ padding: "6px 4px", fontFamily: "var(--mono)", fontSize: 10, color: "#5A6890", letterSpacing: ".6px" }}>
            © 2025 NautiCAI · v1.0.4
          </div>
        </aside>

        {/* ── Main Area ── */}
        <div className="main">
          {/* Topbar */}
          <header className="topbar">
            <div className="topbar-brand">
              <div className="topbar-logo">🤿</div>
              <div className="topbar-text">
                <h1>NAUTICAI</h1>
                <p>Underwater Anomaly Detection Platform</p>
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <span className="pill"><span className={`dot ${health ? "dot-ok" : "dot-warn"}`} />{health ? "API Connected" : "Connecting…"}</span>
            </div>
          </header>

          {/* Tabs */}
          <nav className="tabs">
            {TABS.map(t => (
              <button key={t.key} className={`tab${tab === t.key ? " active" : ""}`} onClick={() => { setTab(t.key); setError(null); }}>
                {t.icon}  {t.label}
              </button>
            ))}
          </nav>

          {/* Page content */}
          <div className="page">
            <AnimatePresence mode="wait">{renderTab()}</AnimatePresence>
          </div>

          {/* Footer */}
          <footer className="footer">
            NautiCAI — Underwater Anomaly Detection Platform · Powered by YOLOv8 & FastAPI · © 2025
          </footer>
        </div>
      </div>
    </>
  );
}
